({"file_text": "\"\"\"Rewards Platform BD - FastAPI backend.\n\nGamified earning platform: games, tasks, surveys, referrals, VIP tiers,\nwallet (BDT), withdrawals (bKash/Nagad - simulated), and an AI support chatbot.\n\"\"\"\nfrom dotenv import load_dotenv\nload_dotenv()\n\nimport os\nimport uuid\nimport random\nimport secrets\nfrom datetime import datetime, timezone, timedelta\n\nimport jwt\nimport bcrypt\nimport httpx\nfrom fastapi import FastAPI, APIRouter, Request, Response, HTTPException, Depends\nfrom fastapi.middleware.cors import CORSMiddleware\nfrom fastapi.responses import StreamingResponse\nfrom pydantic import BaseModel, EmailStr, Field\nfrom motor.motor_asyncio import AsyncIOMotorClient\nfrom emergentintegrations.llm.chat import LlmChat, UserMessage, TextDelta, StreamDone\n\n# ------------------------------------------------------------------ config\nMONGO_URL = os.environ[\"MONGO_URL\"]\nDB_NAME = os.environ[\"DB_NAME\"]\nJWT_SECRET = os.environ[\"JWT_SECRET\"]\nFRONTEND_URL = os.environ.get(\"FRONTEND_URL\", \"http://localhost:3000\")\nEMERGENT_LLM_KEY = os.environ.get(\"EMERGENT_LLM_KEY\", \"\")\nJWT_ALG = \"HS256\"\nSESSION_DAYS = 7\n\nclient = AsyncIOMotorClient(MONGO_URL)\ndb = client[DB_NAME]\n\napp = FastAPI(title=\"Rewards Platform BD\")\napi = APIRouter(prefix=\"/api\")\n\n# ------------------------------------------------------------------ domain config\nVIP_TIERS = [\n    {\"name\": \"Bronze\", \"threshold\": 0, \"color\": \"#CD7F32\", \"perk\": \"1x earnings\"},\n    {\"name\": \"Silver\", \"threshold\": 500, \"color\": \"#C0C0C0\", \"perk\": \"1.1x earnings\"},\n    {\"name\": \"Gold\", \"threshold\": 1500, \"color\": \"#FFD700\", \"perk\": \"1.25x earnings\"},\n    {\"name\": \"Platinum\", \"threshold\": 3000, \"color\": \"#E5E4E2\", \"perk\": \"1.4x earnings\"},\n    {\"name\": \"Diamond\", \"threshold\": 6000, \"color\": \"#B9F2FF\", \"perk\": \"1.6x earnings\"},\n]\nVIP_MULTIPLIER = {\"Bronze\": 1.0, \"Silver\": 1.1, \"Gold\": 1.25, \"Platinum\": 1.4, \"Diamond\": 1.6}\n\nDAILY_BONUS = 25.0\nREFERRAL_BONUS_REFERRER = 100.0\nREFERRAL_BONUS_NEW = 50.0\nSIGNUP_BONUS = 50.0\nMIN_WITHDRAW = 100.0\nDAILY_GAME_LIMIT = {\"spin\": 10, \"dice\": 10, \"coin\": 10}\nSPIN_SEGMENTS = [0, 5, 10, 20, 5, 50, 10, 100, 0, 25]\n\nSEED_TASKS = [\n    {\"task_id\": \"t-follow-fb\", \"title\": \"Follow us on Facebook\", \"description\": \"Like & follow our official Facebook page.\", \"reward\": 15, \"category\": \"Social\", \"icon\": \"facebook\", \"duration\": \"30 sec\"},\n    {\"task_id\": \"t-join-tg\", \"title\": \"Join Telegram Channel\", \"description\": \"Join our Telegram community for updates.\", \"reward\": 20, \"category\": \"Social\", \"icon\": \"send\", \"duration\": \"30 sec\"},\n    {\"task_id\": \"t-watch-video\", \"title\": \"Watch a 30s Video Ad\", \"description\": \"Watch a short sponsored video fully.\", \"reward\": 10, \"category\": \"Video\", \"icon\": \"play\", \"duration\": \"30 sec\"},\n    {\"task_id\": \"t-install-app\", \"title\": \"Install Partner App\", \"description\": \"Install and open a partner mobile app.\", \"reward\": 50, \"category\": \"Install\", \"icon\": \"download\", \"duration\": \"2 min\"},\n    {\"task_id\": \"t-rate-app\", \"title\": \"Rate us 5 Stars\", \"description\": \"Give us a 5 star rating on the store.\", \"reward\": 25, \"category\": \"Engagement\", \"icon\": \"star\", \"duration\": \"1 min\"},\n    {\"task_id\": \"t-share-ref\", \"title\": \"Share your Referral Link\", \"description\": \"Share your referral link with a friend.\", \"reward\": 15, \"category\": \"Social\", \"icon\": \"share-2\", \"duration\": \"1 min\"},\n    {\"task_id\": \"t-daily-checkin\", \"title\": \"Visit Partner Website\", \"description\": \"Browse a partner website for 1 minute.\", \"reward\": 12, \"category\": \"Browse\", \"icon\": \"globe\", \"duration\": \"1 min\"},\n    {\"task_id\": \"t-newsletter\", \"title\": \"Subscribe to Newsletter\", \"description\": \"Subscribe with your email for offers.\", \"reward\": 18, \"category\": \"Engagement\", \"icon\": \"mail\", \"duration\": \"30 sec\"},\n]\n\nSEED_SURVEYS = [\n    {\n        \"survey_id\": \"s-shopping\", \"title\": \"Online Shopping Habits\", \"reward\": 40, \"category\": \"Lifestyle\",\n        \"description\": \"Tell us how you shop online.\",\n        \"questions\": [\n            {\"q\": \"How often do you shop online?\", \"options\": [\"Daily\", \"Weekly\", \"Monthly\", \"Rarely\"]},\n            {\"q\": \"Preferred payment method?\", \"options\": [\"bKash\", \"Nagad\", \"Card\", \"Cash on Delivery\"]},\n            {\"q\": \"What do you buy most?\", \"options\": [\"Fashion\", \"Electronics\", \"Groceries\", \"Books\"]},\n        ],\n    },\n    {\n        \"survey_id\": \"s-mobile\", \"title\": \"Mobile Usage Survey\", \"reward\": 35, \"category\": \"Technology\",\n        \"description\": \"Share your phone usage habits.\",\n        \"questions\": [\n            {\"q\": \"Hours on phone daily?\", \"options\": [\"<2\", \"2-4\", \"4-6\", \"6+\"]},\n            {\"q\": \"Favourite app category?\", \"options\": [\"Social\", \"Games\", \"Video\", \"Productivity\"]},\n            {\"q\": \"Mobile data provider?\", \"options\": [\"GP\", \"Robi\", \"Banglalink\", \"Teletalk\"]},\n        ],\n    },\n    {\n        \"survey_id\": \"s-food\", \"title\": \"Food & Dining Preferences\", \"reward\": 30, \"category\": \"Lifestyle\",\n        \"description\": \"Your food choices matter.\",\n        \"questions\": [\n            {\"q\": \"Favourite cuisine?\", \"options\": [\"Bengali\", \"Chinese\", \"Fast Food\", \"Indian\"]},\n            {\"q\": \"Order food online?\", \"options\": [\"Often\", \"Sometimes\", \"Rarely\", \"Never\"]},\n        ],\n    },\n]\n\n\n# ------------------------------------------------------------------ helpers\ndef now_utc():\n    return datetime.now(timezone.utc)\n\n\ndef hash_password(pw: str) -> str:\n    return bcrypt.hashpw(pw.encode(), bcrypt.gensalt()).decode()\n\n\ndef verify_password(pw: str, hashed: str) -> bool:\n    try:\n        return bcrypt.checkpw(pw.encode(), hashed.encode())\n    except Exception:\n        return False\n\n\ndef make_jwt(user_id: str) -> str:\n    payload = {\"sub\": user_id, \"exp\": now_utc() + timedelta(days=SESSION_DAYS), \"type\": \"access\"}\n    return jwt.encode(payload, JWT_SECRET, algorithm=JWT_ALG)\n\n\ndef gen_referral_code() -> str:\n    return \"BD-\" + secrets.token_hex(3).upper()\n\n\ndef vip_for_points(points: float) -> str:\n    tier = \"Bronze\"\n    for t in VIP_TIERS:\n        if points >= t[\"threshold\"]:\n            tier = t[\"name\"]\n    return tier\n\n\ndef level_for_xp(xp: float) -> int:\n    return int(xp // 100) + 1\n\n\ndef public_user(u: dict) -> dict:\n    if not u:\n        return u\n    u = {k: v for k, v in u.items() if k not in (\"password_hash\", \"_id\")}\n    u[\"vip_multiplier\"] = VIP_MULTIPLIER.get(u.get(\"vip_tier\", \"Bronze\"), 1.0)\n    u[\"next_tier\"] = next_tier_info(u.get(\"points\", 0))\n    return u\n\n\ndef next_tier_info(points: float):\n    for t in VIP_TIERS:\n        if points < t[\"threshold\"]:\n            return {\"name\": t[\"name\"], \"threshold\": t[\"threshold\"], \"remaining\": round(t[\"threshold\"] - points, 2)}\n    return None\n\n\nasync def set_session_cookie(response: Response, token: str):\n    response.set_cookie(\n        key=\"session_token\", value=token, httponly=True, secure=True,\n        samesite=\"none\", max_age=SESSION_DAYS * 86400, path=\"/\",\n    )\n\n\nasync def create_db_session(user_id: str, token: str):\n    await db.user_sessions.insert_one({\n        \"user_id\": user_id, \"session_token\": token,\n        \"expires_at\": now_utc() + timedelta(days=SESSION_DAYS), \"created_at\": now_utc(),\n    })\n\n\nasync def get_current_user(request: Request) -> dict:\n    token = request.cookies.get(\"session_token\")\n    if not token:\n        auth = request.headers.get(\"Authorization\", \"\")\n        if auth.startswith(\"Bearer \"):\n            token = auth[7:]\n    if not token:\n        raise HTTPException(status_code=401, detail=\"Not authenticated\")\n\n    sess = await db.user_sessions.find_one({\"session_token\": token})\n    if sess:\n        exp = sess[\"expires_at\"]\n        if isinstance(exp, str):\n            exp = datetime.fromisoformat(exp)\n        if exp.tzinfo is None:\n            exp = exp.replace(tzinfo=timezone.utc)\n        if exp < now_utc():\n            raise HTTPException(status_code=401, detail=\"Session expired\")\n        user = await db.users.find_one({\"user_id\": sess[\"user_id\"]}, {\"_id\": 0})\n        if not user:\n            raise HTTPException(status_code=401, detail=\"User not found\")\n        return user\n\n    # fallback: decode as JWT\n    try:\n        payload = jwt.decode(token, JWT_SECRET, algorithms=[JWT_ALG])\n        user = await db.users.find_one({\"user_id\": payload[\"sub\"]}, {\"_id\": 0})\n        if not user:\n            raise HTTPException(status_code=401, detail=\"User not found\")\n        return user\n    except jwt.PyJWTError:\n        raise HTTPException(status_code=401, detail=\"Invalid token\")\n\n\nasync def record_activity(user_id: str, atype: str, description: str, amount: float, balance_after: float):\n    await db.activities.insert_one({\n        \"activity_id\": uuid.uuid4().hex, \"user_id\": user_id, \"type\": atype,\n        \"description\": description, \"amount\": round(amount, 2),\n        \"balance_after\": round(balance_after, 2), \"created_at\": now_utc().isoformat(),\n    })\n\n\nasync def award(user: dict, amount: float, atype: str, description: str, count_points: bool = True):\n    \"\"\"Add wallet balance, update points/xp/vip and record activity. Returns updated user.\"\"\"\n    multiplier = VIP_MULTIPLIER.get(user.get(\"vip_tier\", \"Bronze\"), 1.0)\n    earned = round(amount * multiplier, 2) if amount > 0 else round(amount, 2)\n    new_wallet = round(user.get(\"wallet\", 0) + earned, 2)\n    new_points = user.get(\"points\", 0) + (earned if (count_points and earned > 0) else 0)\n    new_xp = user.get(\"xp\", 0) + (earned if earned > 0 else 0)\n    new_vip = vip_for_points(new_points)\n    new_level = level_for_xp(new_xp)\n    update = {\n        \"wallet\": new_wallet, \"points\": round(new_points, 2),\n        \"xp\": round(new_xp, 2), \"vip_tier\": new_vip, \"level\": new_level,\n        \"total_earned\": round(user.get(\"total_earned\", 0) + (earned if earned > 0 else 0), 2),\n    }\n    await db.users.update_one({\"user_id\": user[\"user_id\"]}, {\"$set\": update})\n    await record_activity(user[\"user_id\"], atype, description, earned, new_wallet)\n    user.update(update)\n    return user, earned\n\n\ndef today_key():\n    return now_utc().strftime(\"%Y-%m-%d\")\n\n\n# ------------------------------------------------------------------ models\nclass RegisterBody(BaseModel):\n    name: str = Field(min_length=2, max_length=40)\n    email: EmailStr\n    password: str = Field(min_length=6, max_length=72)\n    referral_code: str | None = None\n\n\nclass LoginBody(BaseModel):\n    email: EmailStr\n    password: str\n\n\nclass CoinBody(BaseModel):\n    choice: str  # heads | tails\n\n\nclass SurveyBody(BaseModel):\n    answers: list[str]\n\n\nclass WithdrawBody(BaseModel):\n    method: str  # bkash | nagad\n    number: str\n    amount: float\n\n\nclass ProfileBody(BaseModel):\n    name: str | None = None\n\n\nclass ChatBody(BaseModel):\n    message: str\n    session_id: str\n\n\n# ------------------------------------------------------------------ auth routes\n@api.post(\"/auth/register\")\nasync def register(body: RegisterBody, response: Response):\n    email = body.email.lower().strip()\n    if await db.users.find_one({\"email\": email}):\n        raise HTTPException(status_code=400, detail=\"Email already registered\")\n\n    user_id = f\"user_{uuid.uuid4().hex[:12]}\"\n    user = {\n        \"user_id\": user_id, \"email\": email, \"name\": body.name.strip(),\n        \"password_hash\": hash_password(body.password), \"picture\": \"\",\n        \"role\": \"user\", \"auth_provider\": \"password\",\n        \"wallet\": 0.0, \"points\": 0.0, \"xp\": 0.0, \"level\": 1, \"vip_tier\": \"Bronze\",\n        \"total_earned\": 0.0, \"referral_code\": gen_referral_code(),\n        \"referred_by\": None, \"total_referrals\": 0, \"referral_earnings\": 0.0,\n        \"daily_bonus_last\": None, \"created_at\": now_utc().isoformat(), \"last_login\": now_utc().isoformat(),\n    }\n    await db.users.insert_one(user)\n    await award(user, SIGNUP_BONUS, \"SIGNUP\", \"Welcome signup bonus\", count_points=True)\n\n    # referral handling\n    if body.referral_code:\n        ref = await db.users.find_one({\"referral_code\": body.referral_code.strip().upper()})\n        if ref and ref[\"user_id\"] != user_id:\n            await db.users.update_one({\"user_id\": user_id}, {\"$set\": {\"referred_by\": ref[\"user_id\"]}})\n            await db.users.update_one(\n                {\"user_id\": ref[\"user_id\"]},\n                {\"$inc\": {\"total_referrals\": 1, \"referral_earnings\": REFERRAL_BONUS_REFERRER}},\n            )\n            ref_fresh = await db.users.find_one({\"user_id\": ref[\"user_id\"]}, {\"_id\": 0})\n            await award(ref_fresh, REFERRAL_BONUS_REFERRER, \"REFERRAL\", f\"Referral bonus: {body.name}\", count_points=True)\n            user_fresh = await db.users.find_one({\"user_id\": user_id}, {\"_id\": 0})\n            await award(user_fresh, REFERRAL_BONUS_NEW, \"REFERRAL\", \"Referral signup bonus\", count_points=True)\n\n    token = make_jwt(user_id)\n    await create_db_session(user_id, token)\n    await set_session_cookie(response, token)\n    fresh = await db.users.find_one({\"user_id\": user_id}, {\"_id\": 0})\n    return {\"user\": public_user(fresh), \"token\": token}\n\n\n@api.post(\"/auth/login\")\nasync def login(body: LoginBody, response: Response):\n    email = body.email.lower().strip()\n    user = await db.users.find_one({\"email\": email})\n    if not user or not user.get(\"password_hash\") or not verify_password(body.password, user[\"password_hash\"]):\n        raise HTTPException(status_code=401, detail=\"Invalid email or password\")\n    await db.users.update_one({\"user_id\": user[\"user_id\"]}, {\"$set\": {\"last_login\": now_utc().isoformat()}})\n    token = make_jwt(user[\"user_id\"])\n    await create_db_session(user[\"user_id\"], token)\n    await set_session_cookie(response, token)\n    return {\"user\": public_user(user), \"token\": token}\n\n\n@api.post(\"/auth/session\")\nasync def google_session(request: Request, response: Response):\n    \"\"\"Exchange Emergent OAuth session_id for an app session.\"\"\"\n    session_id = request.headers.get(\"X-Session-ID\")\n    if not session_id:\n        body = await request.json()\n        session_id = body.get(\"session_id\")\n    if not session_id:\n        raise HTTPException(status_code=400, detail=\"Missing session_id\")\n\n    async with httpx.AsyncClient() as hc:\n        r = await hc.get(\n            \"https://demobackend.emergentagent.com/auth/v1/env/oauth/session-data\",\n            headers={\"X-Session-ID\": session_id},\n        )\n    if r.status_code != 200:\n        raise HTTPException(status_code=401, detail=\"Invalid session\")\n    data = r.json()\n    email = data[\"email\"].lower().strip()\n\n    user = await db.users.find_one({\"email\": email})\n    if not user:\n        user_id = f\"user_{uuid.uuid4().hex[:12]}\"\n        user = {\n            \"user_id\": user_id, \"email\": email, \"name\": data.get(\"name\", \"Player\"),\n            \"password_hash\": None, \"picture\": data.get(\"picture\", \"\"),\n            \"role\": \"user\", \"auth_provider\": \"google\",\n            \"wallet\": 0.0, \"points\": 0.0, \"xp\": 0.0, \"level\": 1, \"vip_tier\": \"Bronze\",\n            \"total_earned\": 0.0, \"referral_code\": gen_referral_code(),\n            \"referred_by\": None, \"total_referrals\": 0, \"referral_earnings\": 0.0,\n            \"daily_bonus_last\": None, \"created_at\": now_utc().isoformat(), \"last_login\": now_utc().isoformat(),\n        }\n        await db.users.insert_one(user)\n        await award(user, SIGNUP_BONUS, \"SIGNUP\", \"Welcome signup bonus\", count_points=True)\n        user = await db.users.find_one({\"user_id\": user_id})\n    else:\n        await db.users.update_one(\n            {\"user_id\": user[\"user_id\"]},\n            {\"$set\": {\"last_login\": now_utc().isoformat(), \"picture\": data.get(\"picture\", user.get(\"picture\", \"\"))}},\n        )\n\n    token = data.get(\"session_token\") or make_jwt(user[\"user_id\"])\n    await create_db_session(user[\"user_id\"], token)\n    await set_session_cookie(response, token)\n    fresh = await db.users.find_one({\"user_id\": user[\"user_id\"]}, {\"_id\": 0})\n    return {\"user\": public_user(fresh), \"token\": token}\n\n\n@api.get(\"/auth/me\")\nasync def me(user: dict = Depends(get_current_user)):\n    return public_user(user)\n\n\n@api.post(\"/auth/logout\")\nasync def logout(request: Request, response: Response):\n    token = request.cookies.get(\"session_token\")\n    if token:\n        await db.user_sessions.delete_many({\"session_token\": token})\n    response.delete_cookie(\"session_token\", path=\"/\")\n    return {\"ok\": True}\n\n\n@api.put(\"/me\")\nasync def update_profile(body: ProfileBody, user: dict = Depends(get_current_user)):\n    update = {}\n    if body.name:\n        update[\"name\"] = body.name.strip()\n    if update:\n        await db.users.update_one({\"user_id\": user[\"user_id\"]}, {\"$set\": update})\n    fresh = await db.users.find_one({\"user_id\": user[\"user_id\"]}, {\"_id\": 0})\n    return public_user(fresh)\n\n\n# ------------------------------------------------------------------ wallet / activity\n@api.get(\"/activities\")\nasync def activities(user: dict = Depends(get_current_user)):\n    items = await db.activities.find(\n        {\"user_id\": user[\"user_id\"]}, {\"_id\": 0}\n    ).sort(\"created_at\", -1).limit(50).to_list(50)\n    return items\n\n\n@api.post(\"/daily-bonus/claim\")\nasync def claim_daily(user: dict = Depends(get_current_user)):\n    last = user.get(\"daily_bonus_last\")\n    if last:\n        last_dt = datetime.fromisoformat(last)\n        if last_dt.tzinfo is None:\n            last_dt = last_dt.replace(tzinfo=timezone.utc)\n        if now_utc() - last_dt < timedelta(hours=24):\n            remaining = timedelta(hours=24) - (now_utc() - last_dt)\n            raise HTTPException(status_code=400, detail=f\"Already claimed. Try again in {int(remaining.total_seconds()//3600)}h.\")\n    await db.users.update_one({\"user_id\": user[\"user_id\"]}, {\"$set\": {\"daily_bonus_last\": now_utc().isoformat()}})\n    user, earned = await award(user, DAILY_BONUS, \"DAILY_BONUS\", \"Daily check-in bonus\")\n    return {\"earned\": earned, \"wallet\": user[\"wallet\"], \"message\": f\"You earned \u09f3{earned} daily bonus!\"}\n\n\n# ------------------------------------------------------------------ games\nasync def game_plays_today(user_id: str, game: str) -> int:\n    return await db.game_plays.count_documents({\"user_id\": user_id, \"game\": game, \"day\": today_key()})\n\n\nasync def log_game(user_id: str, game: str, result, reward: float):\n    await db.game_plays.insert_one({\n        \"user_id\": user_id, \"game\": game, \"result\": result, \"reward\": reward,\n        \"day\": today_key(), \"created_at\": now_utc().isoformat(),\n    })\n\n\n@api.get(\"/games/status\")\nasync def games_status(user: dict = Depends(get_current_user)):\n    out = {}\n    for g, limit in DAILY_GAME_LIMIT.items():\n        played = await game_plays_today(user[\"user_id\"], g)\n        out[g] = {\"played\": played, \"limit\": limit, \"remaining\": max(0, limit - played)}\n    return out\n\n\n@api.post(\"/games/spin\")\nasync def spin(user: dict = Depends(get_current_user)):\n    if await game_plays_today(user[\"user_id\"], \"spin\") >= DAILY_GAME_LIMIT[\"spin\"]:\n        raise HTTPException(status_code=400, detail=\"Daily spin limit reached. Come back tomorrow!\")\n    idx = random.randrange(len(SPIN_SEGMENTS))\n    reward = float(SPIN_SEGMENTS[idx])\n    await log_game(user[\"user_id\"], \"spin\", idx, reward)\n    earned = 0.0\n    if reward > 0:\n        user, earned = await award(user, reward, \"GAME_SPIN\", f\"Lucky Spin won \u09f3{reward}\")\n    return {\"segment_index\": idx, \"segments\": SPIN_SEGMENTS, \"reward\": earned, \"wallet\": user[\"wallet\"]}\n\n\n@api.post(\"/games/dice\")\nasync def dice(user: dict = Depends(get_current_user)):\n    if await game_plays_today(user[\"user_id\"], \"dice\") >= DAILY_GAME_LIMIT[\"dice\"]:\n        raise HTTPException(status_code=400, detail=\"Daily dice limit reached. Come back tomorrow!\")\n    roll = random.randint(1, 6)\n    reward = float(roll * 5)\n    await log_game(user[\"user_id\"], \"dice\", roll, reward)\n    user, earned = await award(user, reward, \"GAME_DICE\", f\"Dice rolled {roll}, won \u09f3{reward}\")\n    return {\"roll\": roll, \"reward\": earned, \"wallet\": user[\"wallet\"]}\n\n\n@api.post(\"/games/coin\")\nasync def coin(body: CoinBody, user: dict = Depends(get_current_user)):\n    if body.choice not in (\"heads\", \"tails\"):\n        raise HTTPException(status_code=400, detail=\"Invalid choice\")\n    if await game_plays_today(user[\"user_id\"], \"coin\") >= DAILY_GAME_LIMIT[\"coin\"]:\n        raise HTTPException(status_code=400, detail=\"Daily coin flip limit reached. Come back tomorrow!\")\n    outcome = random.choice([\"heads\", \"tails\"])\n    won = outcome == body.choice\n    reward = 20.0 if won else 0.0\n    await log_game(user[\"user_id\"], \"coin\", outcome, reward)\n    earned = 0.0\n    if won:\n        user, earned = await award(user, reward, \"GAME_COIN\", f\"Coin Flip won \u09f3{reward}\")\n    return {\"outcome\": outcome, \"won\": won, \"reward\": earned, \"wallet\": user[\"wallet\"]}\n\n\n# ------------------------------------------------------------------ tasks / offers\n@api.get(\"/tasks\")\nasync def list_tasks(user: dict = Depends(get_current_user)):\n    completed = await db.task_completions.find({\"user_id\": user[\"user_id\"]}, {\"_id\": 0, \"task_id\": 1}).to_list(200)\n    done = {c[\"task_id\"] for c in completed}\n    tasks = await db.tasks.find({}, {\"_id\": 0}).to_list(200)\n    for t in tasks:\n        t[\"completed\"] = t[\"task_id\"] in done\n    return tasks\n\n\n@api.post(\"/tasks/{task_id}/complete\")\nasync def complete_task(task_id: str, user: dict = Depends(get_current_user)):\n    task = await db.tasks.find_one({\"task_id\": task_id}, {\"_id\": 0})\n    if not task:\n        raise HTTPException(status_code=404, detail=\"Task not found\")\n    if await db.task_completions.find_one({\"user_id\": user[\"user_id\"], \"task_id\": task_id}):\n        raise HTTPException(status_code=400, detail=\"Task already completed\")\n    await db.task_completions.insert_one({\n        \"user_id\": user[\"user_id\"], \"task_id\": task_id, \"completed_at\": now_utc().isoformat(),\n    })\n    user, earned = await award(user, float(task[\"reward\"]), \"TASK\", f\"Completed: {task['title']}\")\n    return {\"earned\": earned, \"wallet\": user[\"wallet\"]}\n\n\n# ------------------------------------------------------------------ surveys\n@api.get(\"/surveys\")\nasync def list_surveys(user: dict = Depends(get_current_user)):\n    completed = await db.survey_completions.find({\"user_id\": user[\"user_id\"]}, {\"_id\": 0, \"survey_id\": 1}).to_list(200)\n    done = {c[\"survey_id\"] for c in completed}\n    surveys = await db.surveys.find({}, {\"_id\": 0}).to_list(200)\n    for s in surveys:\n        s[\"completed\"] = s[\"survey_id\"] in done\n    return surveys\n\n\n@api.post(\"/surveys/{survey_id}/submit\")\nasync def submit_survey(survey_id: str, body: SurveyBody, user: dict = Depends(get_current_user)):\n    survey = await db.surveys.find_one({\"survey_id\": survey_id}, {\"_id\": 0})\n    if not survey:\n        raise HTTPException(status_code=404, detail=\"Survey not found\")\n    if await db.survey_completions.find_one({\"user_id\": user[\"user_id\"], \"survey_id\": survey_id}):\n        raise HTTPException(status_code=400, detail=\"Survey already completed\")\n    if len(body.answers) < len(survey[\"questions\"]):\n        raise HTTPException(status_code=400, detail=\"Please answer all questions\")\n    await db.survey_completions.insert_one({\n        \"user_id\": user[\"user_id\"], \"survey_id\": survey_id,\n        \"answers\": body.answers, \"completed_at\": now_utc().isoformat(),\n    })\n    user, earned = await award(user, float(survey[\"reward\"]), \"SURVEY\", f\"Survey: {survey['title']}\")\n    return {\"earned\": earned, \"wallet\": user[\"wallet\"]}\n\n\n# ------------------------------------------------------------------ referral\n@api.get(\"/referral\")\nasync def referral_info(user: dict = Depends(get_current_user)):\n    referred = await db.users.find(\n        {\"referred_by\": user[\"user_id\"]}, {\"_id\": 0, \"name\": 1, \"created_at\": 1, \"vip_tier\": 1}\n    ).sort(\"created_at\", -1).to_list(100)\n    return {\n        \"referral_code\": user[\"referral_code\"],\n        \"total_referrals\": user.get(\"total_referrals\", 0),\n        \"referral_earnings\": user.get(\"referral_earnings\", 0.0),\n        \"bonus_per_referral\": REFERRAL_BONUS_REFERRER,\n        \"referred_users\": referred,\n    }\n\n\n# ------------------------------------------------------------------ withdrawals (simulated)\n@api.get(\"/withdrawals\")\nasync def list_withdrawals(user: dict = Depends(get_current_user)):\n    items = await db.withdrawals.find(\n        {\"user_id\": user[\"user_id\"]}, {\"_id\": 0}\n    ).sort(\"created_at\", -1).to_list(50)\n    return items\n\n\n@api.post(\"/withdrawals\")\nasync def create_withdrawal(body: WithdrawBody, user: dict = Depends(get_current_user)):\n    if body.method not in (\"bkash\", \"nagad\"):\n        raise HTTPException(status_code=400, detail=\"Invalid method\")\n    if not body.number or len(body.number.strip()) < 11:\n        raise HTTPException(status_code=400, detail=\"Enter a valid 11-digit mobile number\")\n    if body.amount < MIN_WITHDRAW:\n        raise HTTPException(status_code=400, detail=f\"Minimum withdrawal is \u09f3{MIN_WITHDRAW}\")\n    if body.amount > user.get(\"wallet\", 0):\n        raise HTTPException(status_code=400, detail=\"Insufficient balance\")\n\n    new_wallet = round(user[\"wallet\"] - body.amount, 2)\n    await db.users.update_one({\"user_id\": user[\"user_id\"]}, {\"$set\": {\"wallet\": new_wallet}})\n    wid = \"WD-\" + secrets.token_hex(4).upper()\n    record = {\n        \"withdrawal_id\": wid, \"user_id\": user[\"user_id\"], \"method\": body.method,\n        \"number\": body.number.strip(), \"amount\": round(body.amount, 2),\n        \"status\": \"pending\", \"created_at\": now_utc().isoformat(),\n    }\n    await db.withdrawals.insert_one(record)\n    await record_activity(user[\"user_id\"], \"WITHDRAW\", f\"Withdrawal via {body.method.title()}\", -body.amount, new_wallet)\n    record.pop(\"_id\", None)\n    return {\"withdrawal\": record, \"wallet\": new_wallet, \"message\": \"Withdrawal request submitted (processing simulated).\"}\n\n\n# ------------------------------------------------------------------ leaderboard\n@api.get(\"/leaderboard\")\nasync def leaderboard(user: dict = Depends(get_current_user)):\n    top = await db.users.find(\n        {}, {\"_id\": 0, \"name\": 1, \"points\": 1, \"vip_tier\": 1, \"picture\": 1, \"user_id\": 1, \"total_earned\": 1}\n    ).sort(\"total_earned\", -1).limit(20).to_list(20)\n    for i, t in enumerate(top):\n        t[\"rank\"] = i + 1\n        t[\"is_me\"] = t[\"user_id\"] == user[\"user_id\"]\n        t.pop(\"user_id\", None)\n    return top\n\n\n# ------------------------------------------------------------------ AI chatbot\nSYSTEM_PROMPT = (\n    \"You are 'Robo', the friendly AI support assistant for 'Rewards Platform BD', \"\n    \"a Bangladeshi rewards/earning app where users play games (Lucky Spin, Dice Roll, Coin Flip), \"\n    \"complete tasks/offers, answer surveys to earn Taka (\u09f3), refer friends for bonuses, climb VIP tiers \"\n    \"(Bronze, Silver, Gold, Platinum, Diamond), claim a daily bonus, and withdraw earnings via bKash or Nagad \"\n    \"(minimum \u09f3100). Help users warmly and concisely. You can reply in Bangla or English matching the user's language. \"\n    \"Keep answers short, helpful and encouraging. Never invent payout guarantees; withdrawals are processed manually.\"\n)\n\n\n@api.get(\"/chat/history\")\nasync def chat_history(session_id: str, user: dict = Depends(get_current_user)):\n    msgs = await db.chat_messages.find(\n        {\"user_id\": user[\"user_id\"], \"session_id\": session_id}, {\"_id\": 0}\n    ).sort(\"created_at\", 1).to_list(100)\n    return msgs\n\n\n@api.post(\"/chat\")\nasync def chat(body: ChatBody, user: dict = Depends(get_current_user)):\n    history = await db.chat_messages.find(\n        {\"user_id\": user[\"user_id\"], \"session_id\": body.session_id}, {\"_id\": 0}\n    ).sort(\"created_at\", 1).to_list(20)\n\n    context = SYSTEM_PROMPT\n    if history:\n        convo = \"\\n\".join(f\"{m['role'].title()}: {m['content']}\" for m in history[-10:])\n        context += \"\\n\\nRecent conversation:\\n\" + convo\n    context += f\"\\n\\nThe current user's name is {user.get('name','Player')} and their wallet balance is \u09f3{user.get('wallet',0)}.\"\n\n    await db.chat_messages.insert_one({\n        \"user_id\": user[\"user_id\"], \"session_id\": body.session_id, \"role\": \"user\",\n        \"content\": body.message, \"created_at\": now_utc().isoformat(),\n    })\n\n    chat_client = LlmChat(\n        api_key=EMERGENT_LLM_KEY, session_id=f\"{user['user_id']}-{body.session_id}\",\n        system_message=context,\n    ).with_model(\"anthropic\", \"claude-sonnet-4-6\")\n\n    async def event_gen():\n        full = \"\"\n        try:\n            async for event in chat_client.stream_message(UserMessage(text=body.message)):\n                if isinstance(event, TextDelta):\n                    full += event.content\n                    yield event.content\n                elif isinstance(event, StreamDone):\n                    break\n        except Exception as e:\n            yield f\"\\n[Sorry, I had trouble responding. Please try again.]\"\n            full = full or \"error\"\n        await db.chat_messages.insert_one({\n            \"user_id\": user[\"user_id\"], \"session_id\": body.session_id, \"role\": \"assistant\",\n            \"content\": full, \"created_at\": now_utc().isoformat(),\n        })\n\n    return StreamingResponse(\n        event_gen(), media_type=\"text/plain\",\n        headers={\"Cache-Control\": \"no-cache\", \"X-Accel-Buffering\": \"no\"},\n    )\n\n\n@api.get(\"/config\")\nasync def get_config():\n    return {\n        \"vip_tiers\": VIP_TIERS, \"daily_bonus\": DAILY_BONUS, \"min_withdraw\": MIN_WITHDRAW,\n        \"referral_bonus\": REFERRAL_BONUS_REFERRER, \"game_limits\": DAILY_GAME_LIMIT,\n        \"spin_segments\": SPIN_SEGMENTS,\n    }\n\n\n@api.get(\"/health\")\nasync def health():\n    return {\"status\": \"ok\"}\n\n\n# ------------------------------------------------------------------ startup\n@app.on_event(\"startup\")\nasync def startup():\n    await db.users.create_index(\"email\", unique=True)\n    await db.users.create_index(\"user_id\", unique=True)\n    await db.users.create_index(\"referral_code\")\n    await db.user_sessions.create_index(\"session_token\")\n    await db.activities.create_index([(\"user_id\", 1), (\"created_at\", -1)])\n\n    for t in SEED_TASKS:\n        await db.tasks.update_one({\"task_id\": t[\"task_id\"]}, {\"$set\": t}, upsert=True)\n    for s in SEED_SURVEYS:\n        await db.surveys.update_one({\"survey_id\": s[\"survey_id\"]}, {\"$set\": s}, upsert=True)\n\n    # seed admin\n    admin_email = os.environ.get(\"ADMIN_EMAIL\", \"admin@rewardsbd.com\")\n    admin_pw = os.environ.get(\"ADMIN_PASSWORD\", \"Admin@2026\")\n    existing = await db.users.find_one({\"email\": admin_email})\n    if not existing:\n        admin_id = f\"user_{uuid.uuid4().hex[:12]}\"\n        admin = {\n            \"user_id\": admin_id, \"email\": admin_email, \"name\": \"Admin\",\n            \"password_hash\": hash_password(admin_pw), \"picture\": \"\", \"role\": \"admin\",\n            \"auth_provider\": \"password\", \"wallet\": 0.0, \"points\": 0.0, \"xp\": 0.0, \"level\": 1,\n            \"vip_tier\": \"Bronze\", \"total_earned\": 0.0, \"referral_code\": gen_referral_code(),\n            \"referred_by\": None, \"total_referrals\": 0, \"referral_earnings\": 0.0,\n            \"daily_bonus_last\": None, \"created_at\": now_utc().isoformat(), \"last_login\": None,\n        }\n        await db.users.insert_one(admin)\n    elif not verify_password(admin_pw, existing.get(\"password_hash\", \"\")):\n        await db.users.update_one({\"email\": admin_email}, {\"$set\": {\"password_hash\": hash_password(admin_pw)}})\n\n\napp.add_middleware(\n    CORSMiddleware,\n    allow_origins=[FRONTEND_URL, \"http://localhost:3000\"],\n    allow_credentials=True,\n    allow_methods=[\"*\"],\n    allow_headers=[\"*\"],\n)\napp.include_router(api)\n", "path": "/app/backend/server.py"})
